.ripple-dot {
  position: absolute;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  pointer-events: none;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.8) 0%, rgba(106, 228, 255, 0.3) 50%, rgba(106, 228, 255, 0) 100%);
  transform: translate(-50%, -50%);
  animation: ripplePulse 0.54s ease-out forwards;
}

.corner-star {
  position: absolute;
  width: 56px;
  height: 56px;
  transform: translate(-50%, -50%);
  pointer-events: none;
  z-index: 3;
  filter: drop-shadow(0 0 6px rgba(255, 246, 198, 0.78)) drop-shadow(0 0 14px rgba(255, 241, 174, 0.48));
  animation: cornerStarBurst 0.74s ease-out forwards;
}

.corner-star::before,
.corner-star::after {
  content: "";
  position: absolute;
  background: radial-gradient(circle at 50% 46%, rgba(255, 255, 246, 0.98) 0%, rgba(255, 248, 214, 0.95) 38%, rgba(255, 241, 170, 0.82) 62%, rgba(255, 241, 170, 0) 100%);
  clip-path: polygon(50% 0%, 60% 28%, 100% 50%, 60% 72%, 50% 100%, 40% 72%, 0% 50%, 40% 28%);
}

.corner-star::before {
  width: 46px;
  height: 46px;
  left: 5px;
  top: 0;
}

.corner-star::after {
  width: 22px;
  height: 22px;
  right: 0;
  bottom: 3px;
  opacity: 0.96;
}

@keyframes ripplePulse {
