:root {
  --bg: #0f1225;
  --bg-deep: #171b36;
  --surface: #ffffff;
  --surface-soft: #f7f9ff;
  --surface-muted: rgba(255, 255, 255, 0.7);
  --border: rgba(224, 230, 255, 0.68);
  --border-strong: rgba(196, 207, 255, 0.9);
  --text: #0f1b38;
  --muted: #4c5878;
  --primary: #7b61ff;
  --primary-strong: #5d43ec;
  --primary-soft: rgba(123, 97, 255, 0.12);
  --accent-cyan: #6ae4ff;
  --accent-pink: #ff78d4;
  --success: #16a34a;
  --success-soft: #e9f9ef;
  --warning: #d97706;
  --warning-soft: #fff4e6;
  --danger: #dc2626;
  --danger-soft: #feecec;
  --shadow: 0 26px 70px rgba(8, 12, 30, 0.18);
  --shadow-soft: 0 14px 30px rgba(17, 23, 52, 0.08);
  --radius-xl: 28px;
  --radius-lg: 22px;
  --radius-md: 14px;
  --radius-sm: 10px;
  --font-ui:
    "Segoe UI Variable Text",
    "Segoe UI",
    "PingFang SC",
    "Hiragino Sans GB",
    "Microsoft YaHei UI",
    "Microsoft YaHei",
    sans-serif;
  --font-display:
    "Segoe UI Variable Display",
    "Segoe UI Variable Text",
    "Segoe UI",
    "PingFang SC",
    "Hiragino Sans GB",
    "Microsoft YaHei UI",
    "Microsoft YaHei",
    sans-serif;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: var(--font-ui);
  background:
    radial-gradient(circle at 18% 8%, rgba(132, 116, 255, 0.24), transparent 22%),
    radial-gradient(circle at 82% 12%, rgba(118, 206, 255, 0.16), transparent 20%),
    radial-gradient(circle at 50% 38%, rgba(255, 154, 210, 0.08), transparent 26%),
    radial-gradient(circle at 50% 88%, rgba(255, 190, 154, 0.18), transparent 20%),
    linear-gradient(180deg, #040814 0%, #08132b 14%, #10224a 30%, #18335e 44%, #2b3f67 56%, #523f6d 72%, #2e2146 86%, #120d22 100%);
  color: var(--text);
  line-height: 1.6;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

button,
input,
select,
textarea {
  font: inherit;
}

h1,
h2,
h3,
h4,
.stat-value,
.requirement-title,
.focus-title-row h3,
.stage-title-wrap h3,
.dashboard-item-title {
  font-family: var(--font-display);
}

button {
  cursor: pointer;
  border: none;
}

textarea,
input,
select {
  width: 100%;
  padding: 12px 14px;
  border: 1px solid var(--border);
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.96);
  color: var(--text);
  transition: border-color 0.18s ease, box-shadow 0.18s ease, background-color 0.18s ease;
}

textarea:focus,
input:focus,
select:focus {
  outline: none;
  border-color: rgba(68, 88, 247, 0.42);
  box-shadow: 0 0 0 4px rgba(68, 88, 247, 0.1);
  background: #fff;
}

textarea {
  resize: vertical;
}

.app-shell {
  position: relative;
  min-height: 100vh;
  padding: 28px 24px 40px;
}

.meteor-field {
  position: fixed;
  inset: 0;
  overflow: hidden;
  pointer-events: none;
  z-index: 0;
  opacity: 0.9;
}

.meteor-field::before,
.meteor-field::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.meteor-field::before {
  background:
    radial-gradient(circle at 18% 20%, rgba(157, 130, 255, 0.18), transparent 18%),
    radial-gradient(circle at 76% 22%, rgba(125, 201, 255, 0.14), transparent 18%),
    radial-gradient(circle at 48% 58%, rgba(255, 170, 214, 0.1), transparent 24%),
    radial-gradient(circle at 52% 92%, rgba(255, 193, 152, 0.14), transparent 20%),
    radial-gradient(58% 22% at 22% 72%, rgba(156, 156, 255, 0.1), transparent 72%),
    radial-gradient(52% 18% at 72% 68%, rgba(255, 205, 179, 0.08), transparent 74%);
  filter: blur(48px);
  opacity: 1;
}

.meteor-field::after {
  background:
    radial-gradient(circle at 10% 14%, rgba(255, 255, 255, 0.22), transparent 1.4px),
    radial-gradient(circle at 18% 28%, rgba(222, 211, 255, 0.18), transparent 1.5px),
    radial-gradient(circle at 30% 10%, rgba(255, 255, 255, 0.16), transparent 1.2px),
    radial-gradient(circle at 42% 22%, rgba(204, 187, 255, 0.16), transparent 1.5px),
    radial-gradient(circle at 56% 12%, rgba(255, 255, 255, 0.16), transparent 1.3px),
    radial-gradient(circle at 68% 18%, rgba(191, 226, 255, 0.16), transparent 1.5px),
    radial-gradient(circle at 80% 10%, rgba(255, 255, 255, 0.16), transparent 1.3px),
    radial-gradient(circle at 88% 26%, rgba(225, 205, 255, 0.16), transparent 1.4px),
    radial-gradient(circle at 20% 46%, rgba(255, 255, 255, 0.14), transparent 1.2px),
    radial-gradient(circle at 34% 58%, rgba(220, 204, 255, 0.14), transparent 1.4px),
    radial-gradient(circle at 52% 44%, rgba(255, 255, 255, 0.14), transparent 1.2px),
    radial-gradient(circle at 70% 52%, rgba(207, 226, 255, 0.14), transparent 1.4px),
    radial-gradient(circle at 84% 62%, rgba(255, 255, 255, 0.14), transparent 1.3px),
    radial-gradient(circle at 14% 74%, rgba(229, 214, 255, 0.12), transparent 1.3px),
    radial-gradient(circle at 46% 80%, rgba(255, 255, 255, 0.12), transparent 1.2px),
    radial-gradient(circle at 76% 78%, rgba(255, 229, 241, 0.12), transparent 1.3px),
    radial-gradient(circle at 92% 86%, rgba(202, 182, 255, 0.12), transparent 1.2px);
  opacity: 0.88;
}

.meteor {
  position: absolute;
  top: -12%;
  left: -24%;
  width: 220px;
  height: 2px;
  border-radius: 999px;
  background: linear-gradient(90deg, rgba(255, 255, 255, 0) 0%, rgba(104, 221, 255, 0.04) 10%, rgba(194, 160, 255, 0.88) 28%, rgba(255, 226, 171, 0.72) 48%, rgba(255, 255, 255, 0.08) 100%);
  box-shadow:
    0 0 12px rgba(142, 216, 255, 0.24),
    0 0 22px rgba(155, 118, 255, 0.32),
    0 0 38px rgba(255, 186, 138, 0.16);
  opacity: 0;
  transform: rotate(24deg);
  filter: blur(0.2px);
  animation: meteorFall 12s linear infinite, meteorPulse 3.6s ease-in-out infinite;
}

.meteor::before {
  content: "";
  position: absolute;
  right: 4px;
  top: 50%;
  width: 13px;
  height: 13px;
  border-radius: 50%;
  transform: translateY(-50%);
  background: radial-gradient(circle, rgba(255, 255, 255, 1) 0%, rgba(195, 236, 255, 0.96) 24%, rgba(255, 227, 164, 0.92) 46%, rgba(169, 128, 255, 0.4) 100%);
  box-shadow:
    0 0 12px rgba(255, 255, 255, 0.68),
    0 0 22px rgba(120, 218, 255, 0.34),
    0 0 38px rgba(255, 203, 130, 0.3);
}

.meteor::after {
  content: "";
  position: absolute;
  right: 24px;
  top: 50%;
  width: 160px;
  height: 18px;
  transform: translateY(-50%);
  border-radius: 999px;
  background:
    linear-gradient(90deg, rgba(255, 255, 255, 0) 0%, rgba(198, 171, 255, 0.18) 32%, rgba(255, 224, 177, 0.12) 56%, rgba(255, 255, 255, 0) 100%);
  filter: blur(8px);
  opacity: 0.92;
}

.meteor:nth-child(1) {
  top: 10%;
  animation-delay: 0s;
  animation-duration: 8.6s;
  width: 250px;
}

.meteor:nth-child(2) {
  top: 18%;
  animation-delay: 1.8s;
  animation-duration: 10.2s;
  width: 280px;
}

.meteor:nth-child(3) {
  top: 28%;
  animation-delay: 4.2s;
  animation-duration: 9.6s;
  width: 210px;
}

.meteor:nth-child(4) {
  top: 40%;
  animation-delay: 6.4s;
  animation-duration: 11s;
  width: 240px;
}

.meteor:nth-child(5) {
  top: 52%;
  animation-delay: 8.2s;
  animation-duration: 9.8s;
  width: 225px;
}

.meteor:nth-child(6) {
  top: 64%;
  animation-delay: 2.7s;
  animation-duration: 11.4s;
  width: 210px;
}

.meteor:nth-child(7) {
  top: 14%;
  animation-delay: 3.3s;
  animation-duration: 9.1s;
  width: 205px;
}

.meteor:nth-child(8) {
  top: 24%;
  animation-delay: 5.1s;
  animation-duration: 10.4s;
  width: 260px;
}

.meteor:nth-child(9) {
  top: 34%;
  animation-delay: 7.2s;
  animation-duration: 8.9s;
  width: 215px;
}

.meteor:nth-child(10) {
  top: 46%;
  animation-delay: 1.1s;
  animation-duration: 10.8s;
  width: 235px;
}

.meteor:nth-child(11) {
  top: 58%;
  animation-delay: 4.6s;
  animation-duration: 9.7s;
  width: 220px;
}

.meteor:nth-child(12) {
  top: 72%;
  animation-delay: 6.8s;
  animation-duration: 11.3s;
  width: 210px;
}

.app-shell::before {
  content: "";
  position: fixed;
  inset: 0;
  background:
    radial-gradient(circle at 14% 16%, rgba(135, 112, 255, 0.12), transparent 18%),
    radial-gradient(circle at 76% 24%, rgba(112, 189, 255, 0.1), transparent 20%),
    radial-gradient(circle at 48% 62%, rgba(255, 162, 210, 0.08), transparent 22%),
    radial-gradient(circle at 50% 94%, rgba(255, 194, 160, 0.14), transparent 18%);
  pointer-events: none;
  filter: blur(26px);
}

.app-shell::after {
  content: "";
  position: fixed;
  inset: 0;
  background:
    radial-gradient(circle at 12% 12%, rgba(255, 255, 255, 0.12), transparent 1.4px),
    radial-gradient(circle at 24% 22%, rgba(232, 217, 255, 0.1), transparent 1.5px),
    radial-gradient(circle at 38% 8%, rgba(255, 255, 255, 0.1), transparent 1.4px),
    radial-gradient(circle at 54% 16%, rgba(210, 193, 255, 0.1), transparent 1.5px),
    radial-gradient(circle at 72% 12%, rgba(255, 255, 255, 0.1), transparent 1.4px),
    radial-gradient(circle at 86% 18%, rgba(201, 228, 255, 0.1), transparent 1.6px),
    radial-gradient(circle at 18% 70%, rgba(255, 255, 255, 0.08), transparent 1.4px),
    radial-gradient(circle at 44% 82%, rgba(225, 207, 255, 0.08), transparent 1.5px),
    radial-gradient(circle at 78% 74%, rgba(255, 255, 255, 0.08), transparent 1.4px);
  pointer-events: none;
  opacity: 0.86;
}

.app-frame {
  position: relative;
  max-width: 1560px;
  margin: 0 auto;
}

.topbar {
  position: relative;
  display: flex;
  justify-content: space-between;
  gap: 24px;
  align-items: stretch;
  margin-bottom: 20px;
  padding: 28px 30px;
  overflow: hidden;
  background:
    linear-gradient(135deg, rgba(255, 255, 255, 0.18) 0%, rgba(255, 255, 255, 0.07) 28%, rgba(255, 255, 255, 0.03) 100%),
    radial-gradient(circle at 16% 16%, rgba(129, 100, 255, 0.22), transparent 22%),
    radial-gradient(circle at 80% 8%, rgba(95, 217, 255, 0.22), transparent 24%),
    linear-gradient(180deg, rgba(8, 14, 34, 0.72) 0%, rgba(11, 20, 48, 0.7) 24%, rgba(24, 34, 78, 0.66) 56%, rgba(66, 52, 92, 0.62) 82%, rgba(149, 94, 107, 0.6) 100%);
  color: #fff;
  border: 1px solid rgba(255, 255, 255, 0.2);
  box-shadow:
    0 22px 60px rgba(6, 10, 22, 0.24),
    inset 0 1px 0 rgba(255, 255, 255, 0.22),
    inset 0 -1px 0 rgba(255, 255, 255, 0.06);
  backdrop-filter: blur(24px) saturate(140%);
  -webkit-backdrop-filter: blur(24px) saturate(140%);
}

.topbar::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    linear-gradient(135deg, rgba(255, 255, 255, 0.16) 0%, rgba(255, 255, 255, 0.02) 32%, rgba(255, 255, 255, 0) 60%),
    radial-gradient(circle at 18% 10%, rgba(255, 255, 255, 0.14), transparent 22%);
  pointer-events: none;
}

.topbar::after {
  content: "";
  position: absolute;
  inset: 1px;
  border-radius: inherit;
  border: 1px solid rgba(255, 255, 255, 0.08);
  pointer-events: none;
}

.topbar h1 {
  margin: 6px 0 12px;
  font-size: 36px;
  line-height: 1.15;
  font-weight: 800;
  letter-spacing: -0.02em;
  color: #ffffff;
  text-shadow:
    0 2px 10px rgba(6, 10, 22, 0.36),
    0 0 18px rgba(121, 175, 255, 0.26),
    0 0 30px rgba(143, 112, 255, 0.16);
}

.eyebrow {
  margin: 0;
  color: rgba(255, 255, 255, 0.9);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  text-shadow: 0 1px 6px rgba(5, 9, 20, 0.28);
}

.topbar-copy {
  position: relative;
  z-index: 1;
  max-width: 840px;
  padding: 8px 18px 12px 0;
}

.topbar-copy::before {
  content: "";
  position: absolute;
  inset: -10px 20% -14px -18px;
  border-radius: 28px;
  background:
    linear-gradient(90deg, rgba(7, 12, 28, 0.44) 0%, rgba(12, 18, 42, 0.22) 54%, rgba(12, 18, 42, 0) 100%);
  filter: blur(8px);
  z-index: -1;
}

.brand-line {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 8px;
}

.brand-mark {
  position: relative;
  width: 58px;
  height: 58px;
  flex: 0 0 auto;
  animation: dreamFloat 8s ease-in-out infinite;
}

.brand-orbit,
.brand-core {
  position: absolute;
  inset: 0;
  border-radius: 50%;
}

.brand-orbit {
  border: 1px solid rgba(255, 255, 255, 0.22);
}

.orbit-a {
  transform: rotate(24deg) scale(1, 0.62);
  animation: slowSpin 10s linear infinite;
}

.orbit-b {
  transform: rotate(-28deg) scale(0.68, 1);
  animation: slowSpinReverse 14s linear infinite;
}

.brand-core {
  inset: 18px;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.95) 0%, rgba(106, 228, 255, 0.72) 38%, rgba(123, 97, 255, 0.4) 100%);
  box-shadow:
    0 0 18px rgba(106, 228, 255, 0.34),
    0 0 28px rgba(123, 97, 255, 0.22);
}

.brand-text-group h1 {
  margin-top: 2px;
}

.subtitle {
  margin: 0;
  max-width: 760px;
  color: rgba(255, 255, 255, 0.96);
  line-height: 1.8;
  font-size: 15px;
  font-weight: 600;
  text-shadow:
    0 1px 8px rgba(6, 10, 22, 0.28),
    0 0 12px rgba(89, 123, 255, 0.12);
}

.topbar-actions {
  position: relative;
  z-index: 1;
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  align-content: flex-start;
  justify-content: flex-end;
}

.session-inline-group {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  flex-wrap: nowrap;
}

.hero-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 18px;
}

.hero-tag {
  display: inline-flex;
  align-items: center;
  min-height: 34px;
  padding: 0 14px;
  border-radius: 999px;
  background: rgba(10, 16, 38, 0.28);
  border: 1px solid rgba(255, 255, 255, 0.22);
  color: #ffffff;
  backdrop-filter: blur(8px);
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.01em;
  text-shadow: 0 1px 6px rgba(6, 10, 22, 0.24);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.1),
    0 8px 20px rgba(8, 12, 28, 0.12);
}

.hero-comet-arc,
.hero-comet-trail,
.hero-horizon-glow,
.hero-cloud {
  position: absolute;
  pointer-events: none;
}

.hero-comet-arc {
  top: -96px;
  right: -48px;
  width: 94%;
  height: 286px;
  border-top: 4px solid rgba(113, 236, 255, 0.98);
  border-radius: 50%;
  transform: rotate(6deg);
  box-shadow:
    0 0 20px rgba(104, 230, 255, 0.44),
    0 0 42px rgba(143, 112, 255, 0.28),
    0 0 74px rgba(118, 165, 255, 0.18);
  opacity: 0.98;
}

.hero-comet-arc-secondary {
  top: -78px;
  right: -24px;
  width: 90%;
  height: 260px;
  border-top: 2px solid rgba(206, 144, 255, 0.56);
  box-shadow:
    0 0 24px rgba(196, 132, 255, 0.24),
    0 0 44px rgba(255, 255, 255, 0.08);
  opacity: 0.82;
}

.hero-comet-trail {
  top: 84px;
  right: 45%;
  width: 240px;
  height: 3px;
  border-radius: 999px;
  transform: rotate(122deg);
  background: linear-gradient(90deg, rgba(255, 255, 255, 0) 0%, rgba(255, 217, 148, 0.96) 32%, rgba(255, 255, 255, 0.04) 100%);
  box-shadow:
    0 0 14px rgba(255, 204, 122, 0.4),
    0 0 28px rgba(255, 142, 85, 0.18);
  opacity: 0.96;
}

.hero-comet-trail::before {
  content: "";
  position: absolute;
  right: 0;
  top: 50%;
  width: 11px;
  height: 11px;
  border-radius: 50%;
  transform: translateY(-50%);
  background: radial-gradient(circle, rgba(255, 255, 255, 0.98) 0%, rgba(255, 216, 153, 0.9) 42%, rgba(255, 144, 94, 0.28) 100%);
  box-shadow:
    0 0 14px rgba(255, 255, 255, 0.5),
    0 0 26px rgba(255, 194, 121, 0.42);
}

.hero-horizon-glow {
  left: -8%;
  right: -8%;
  bottom: -18%;
  height: 42%;
  background:
    radial-gradient(circle at 50% 100%, rgba(255, 201, 144, 0.48), transparent 34%),
    linear-gradient(180deg, rgba(255, 178, 126, 0) 0%, rgba(255, 171, 138, 0.22) 46%, rgba(255, 210, 182, 0.42) 100%);
  filter: blur(18px);
  opacity: 0.9;
}

.hero-cloud {
  bottom: -6%;
  height: 28%;
  border-radius: 42% 58% 56% 44% / 56% 52% 48% 44%;
  filter: blur(18px);
  opacity: 0.82;
  animation: cloudDrift 28s ease-in-out infinite;
}

.hero-cloud-a {
  left: -8%;
  width: 58%;
  height: 30%;
  background:
    radial-gradient(34% 52% at 18% 54%, rgba(255, 246, 239, 0.78) 0%, rgba(255, 219, 193, 0.4) 48%, transparent 78%),
    radial-gradient(42% 56% at 46% 46%, rgba(255, 235, 224, 0.78) 0%, rgba(255, 194, 174, 0.34) 46%, transparent 78%),
    radial-gradient(38% 48% at 76% 58%, rgba(215, 233, 255, 0.28) 0%, rgba(177, 206, 255, 0.12) 44%, transparent 78%);
}

.hero-cloud-b {
  right: -6%;
  width: 54%;
  height: 28%;
  background:
    radial-gradient(34% 52% at 24% 56%, rgba(255, 242, 234, 0.72) 0%, rgba(255, 206, 186, 0.32) 48%, transparent 78%),
    radial-gradient(42% 58% at 54% 46%, rgba(255, 232, 223, 0.72) 0%, rgba(250, 184, 176, 0.3) 44%, transparent 78%),
    radial-gradient(30% 44% at 82% 60%, rgba(205, 228, 255, 0.24) 0%, rgba(171, 217, 255, 0.1) 42%, transparent 76%);
  animation-duration: 34s;
  animation-name: cloudDriftReverse;
}

.hero-cloud-c {
  left: 10%;
  bottom: 10%;
  width: 48%;
  height: 20%;
  background:
    radial-gradient(30% 50% at 20% 58%, rgba(222, 236, 255, 0.52) 0%, rgba(170, 194, 255, 0.22) 42%, transparent 76%),
    radial-gradient(38% 54% at 56% 44%, rgba(255, 237, 227, 0.44) 0%, rgba(255, 199, 176, 0.18) 46%, transparent 76%);
  filter: blur(16px);
  opacity: 0.72;
  animation-duration: 24s;
}

.hero-cloud-d {
  right: 8%;
  bottom: 12%;
  width: 38%;
  height: 18%;
  background:
    radial-gradient(30% 54% at 34% 58%, rgba(255, 230, 208, 0.52) 0%, rgba(255, 183, 157, 0.2) 44%, transparent 76%),
    radial-gradient(30% 46% at 70% 42%, rgba(188, 223, 255, 0.28) 0%, rgba(171, 217, 255, 0.12) 42%, transparent 74%);
  filter: blur(14px);
  opacity: 0.68;
  animation-duration: 30s;
  animation-name: cloudDriftReverse;
}

.hero-cloud::before {
  content: "";
  position: absolute;
  inset: 12% 10%;
  border-radius: 50%;
  background:
    radial-gradient(34% 46% at 24% 58%, rgba(255, 255, 255, 0.24) 0%, transparent 72%),
    radial-gradient(30% 40% at 72% 46%, rgba(255, 247, 229, 0.2) 0%, transparent 70%);
  filter: blur(10px);
  opacity: 0.86;
}

.hero-cloud::after {
  content: "";
  position: absolute;
  inset: 18% 12% -4%;
  border-radius: 44% 56% 52% 48% / 58% 60% 40% 42%;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0) 0%, rgba(243, 228, 244, 0.08) 28%, rgba(193, 182, 236, 0.14) 100%);
  filter: blur(12px);
  opacity: 0.72;
}

.hero-glow {
  position: absolute;
  border-radius: 999px;
  filter: blur(18px);
  pointer-events: none;
}

.hero-glow-a {
  right: -80px;
  top: -40px;
  width: 260px;
  height: 260px;
  background: rgba(140, 120, 255, 0.24);
}

.hero-glow-b {
  right: 180px;
  bottom: -80px;
  width: 180px;
  height: 180px;
  background: rgba(106, 228, 255, 0.2);
}

.workspace {
  display: grid;
  grid-template-columns: 340px minmax(0, 1fr);
  gap: 20px;
  align-items: start;
}

.dashboard-panel {
  margin-bottom: 20px;
  padding: 20px;
  background:
    linear-gradient(135deg, rgba(255, 255, 255, 0.18) 0%, rgba(255, 255, 255, 0.09) 30%, rgba(255, 255, 255, 0.05) 100%),
    linear-gradient(180deg, rgba(250, 252, 255, 0.42) 0%, rgba(240, 245, 255, 0.28) 100%);
